#!/usr/bin/env python3
"""
deploy_v19_34_218.py - EXECUTION PILLAR: ALWAYS override win-rate + streak from tape

v217 made the pillar derive live state ONLY when the profile was empty. But on
the live DGX the in-memory profile has total_trades>0 (mutated as trades close)
while its win-rate aggregates to 0 and the tilt counter resets -- so the v217
branch never fired and recent_win_rate (0.5) + consecutive_losses (0) stayed
pinned at 100 pct default in the stored breakdown.

v218: recent_win_rate + consecutive_losses are OBJECTIVE facts from the outcome
tape, so ALWAYS derive them live from trade_outcomes (limit 30) and OVERRIDE the
unreliable profile values whenever any outcomes exist. De-pins tilt(30) + streak(15).

SAFETY: checksum-guarded full-file replace (writes ONLY if on-disk file matches
the v217 sha OR already carries the v218 marker; aborts on drift). Idempotent,
transactional, runs the test, commits + pushes BEFORE restart.

RUN ON THE DGX:
  curl -s https://paste.rs/XXXXX -o /tmp/deploy_v19_34_218.py
  python3 /tmp/deploy_v19_34_218.py
  ./start_backend.sh --force
"""
import os, base64, hashlib, shutil, subprocess, sys, py_compile

REPO = os.path.expanduser("~/Trading-and-Analysis-Platform")
if not os.path.isdir(REPO):
    REPO = os.getcwd()
SVC = os.path.join(REPO, "backend", "services", "tqs", "execution_quality.py")
TEST = os.path.join(REPO, "backend", "tests",
                    "test_v19_34_217_execution_pillar_live_state.py")

MARKER = "v19.34.218"
PREPATCH_SHA = "1536504cfbc4772bd32f80e87e7d2a6a6fa35062d54d652ea8a72b90aaf21a97"
NEW_SVC_SHA = "cf4bcb1e638d4659537202745d04f4543b5ef690c24e964639fa0cd3d2257847"
SVC_B64 = ""
TEST_B64 = ""


def fail(m):
    print("\n[FAIL] " + m); sys.exit(1)


def main():
    print("== deploy_v19_34_218 ==\nrepo: " + REPO)
    if not os.path.isfile(SVC):
        fail("target not found: " + SVC)
    cur = open(SVC, "rb").read()
    cur_sha = hashlib.sha256(cur).hexdigest()
    new_bytes = base64.b64decode(SVC_B64)
    assert hashlib.sha256(new_bytes).hexdigest() == NEW_SVC_SHA, "payload corrupt"

    if MARKER in cur.decode("utf-8", "ignore"):
        print("[ok] already patched (v218 marker) - skipping file write.")
    elif cur_sha == PREPATCH_SHA:
        shutil.copy2(SVC, SVC + ".v218.bak")
        open(SVC, "wb").write(new_bytes)
        try:
            py_compile.compile(SVC, doraise=True)
        except py_compile.PyCompileError as e:
            shutil.copy2(SVC + ".v218.bak", SVC)
            fail("py_compile failed, rolled back: " + str(e))
        os.remove(SVC + ".v218.bak")
        print("[ok] execution_quality.py replaced + compiles clean.")
    else:
        fail("on-disk execution_quality.py matches NEITHER the v217 sha NOR the "
             "v218 marker (sha=" + cur_sha[:12] + "). Drift - aborting WITHOUT changes.")

    os.makedirs(os.path.dirname(TEST), exist_ok=True)
    open(TEST, "wb").write(base64.b64decode(TEST_B64))
    print("[ok] wrote test file")

    print("\n== pytest ==")
    r = subprocess.run([sys.executable, "-m", "pytest", TEST, "-q"],
                       cwd=os.path.join(REPO, "backend"))
    if r.returncode != 0:
        fail("pytest failed - NOT committing.")
    print("[ok] tests green.")

    print("\n== git commit + push ==")
    subprocess.run(["git", "add", "-A"], cwd=REPO)
    cm = subprocess.run(["git", "commit", "-m",
        "v19.34.218 Execution pillar: ALWAYS override recent_win_rate + "
        "consecutive_losses from live trade_outcomes tape"], cwd=REPO)
    if cm.returncode == 0:
        subprocess.run(["git", "push"], cwd=REPO)
        print("[ok] committed + pushed.")
    else:
        print("[info] nothing to commit - skipping push.")

    print("\n[DONE] Restart backend:  ./start_backend.sh --force")
    print("Then re-run:  python3 /tmp/diag_tqs_pillar_breakdown.py --since-min 20")
    print("EXECUTION recent_win_rate + consecutive_losses default-rate should DROP")
    print("well below 100 pct, and the pillar median should move off 48.80.")


if __name__ == "__main__":
    main()
